#include <bits/stdc++.h>
using namespace std;
const int maxn=2e5+5;
struct ss {
	int v,id;
	bool operator<(const ss &aa)const {
		return v<aa.v;
	}
};
int n,m,cnt,du[maxn],cur[maxn],vis[maxn],tot;
vector<ss> g[maxn];
vector<int> ans(maxn);
void dfs(int u) {
	for(int i=cur[u]; i<g[u].size(); i=cur[u]) {
		int v=g[u][i].v,id=g[u][i].id;
		cur[u]=i+1;
		if(vis[id]) {
			continue;
		}
		vis[id]=1;
		dfs(v);
	}
	ans[++tot]=u;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>m;
	set<int> s;
	for(int i=1,u,v; i<=m; i++) {
		cin>>u>>v;
		g[u].push_back({v,i});
		g[v].push_back({u,i});
		du[u]++;
		du[v]++;
	}
	n=500;
	for(int i=1; i<=n; i++) {
		sort(g[i].begin(),g[i].end());
	}
	int st=1;
	for(int i=1; i<=n; i++) {
		if(du[i]%2) {
			cnt++;
		}
	}
//	if(cnt!=0&&cnt!=2) {
//		cout<<"No";
//		return 0;
//	}
	if(cnt==2) {
		for(int i=1; i<=n; i++) {
			if(du[i]%2) {
				st=i;
				break;
			}
		}
	} else {
		for(int i=1; i<=n; i++) {
			if(du[i]>0) {
				st=i;
				break;
			}
		}
	}
	dfs(st);
	for(int i=tot; i>=1; i--) {
		cout<<ans[i]<<"\n";
	}
	return 0;
}
